window.ROTATION_LLM_ABOUT = {"deadmau5~professional-griefers":{"src":"haiku","haiku":"Self-destructive nihilism and technological alienation in a broken world.","sonnet":"A violent, anarchic vision of technological society destroying itself through machines, bombs, and human brutality.","opus":"A dystopian, apocalyptic vision of youth, technology, warfare and self-destruction, presented as a chaotic video-game world of broken, awful things the narrator made."},"nine-inch-nails~wish":{"src":"haiku","haiku":"Despair and isolation amid broken trust and disillusionment with existence.","sonnet":"Alienation and self-loathing in a world that feels hollow and fake, with no authentic connection left to find.","opus":"Self-loathing and bitter despair at rock bottom, having lost faith in God and a partner, wishing for anything real in an empty life."},"linkin-park~somewhere-i-belong":{"src":"haiku","haiku":"Personal emotional void and struggle to find belonging and self-worth.","sonnet":"A person trapped in emptiness and self-blame searching for healing, identity, and a place where they feel they belong.","opus":"Struggling to break free of inner numbness and pain to heal, find identity, and reach a sense of belonging on one's own terms."},"linkin-park~hit-the-floor":{"src":"haiku","haiku":"Confronting betrayal and waiting for redemption through revenge on a manipulator.","sonnet":"Confronting a manipulative person who lies and belittles, and waiting for the moment their power collapses.","opus":"Confronting a manipulative liar who kept you down, and anticipating their inevitable fall once their deceit collapses."},"bring-me-the-horizon~dear-diary":{"src":"haiku","haiku":"Apocalyptic horror scenario with infection and societal collapse.","sonnet":"A zombie apocalypse experienced through diary entries as the narrator gradually succumbs to infection and eats their dog.","opus":"A darkly comic diary of someone descending into a zombie-outbreak apocalypse, going mad and cannibalistic as the human race ends."},"linkin-park~in-the-end":{"src":"haiku","haiku":"Wasted effort in a relationship despite trying hard; ultimate futility and betrayal.","sonnet":"The futility of straining toward a relationship or goal that ultimately falls apart despite every effort made.","opus":"The futility of effort and trust in a failed relationship, realizing that all one's striving ultimately amounts to nothing."},"crystal-castles~concrete":{"src":"sonnet","sonnet":"The dismantling of fixed belief and certainty, leaving nothing permanent or solid in its place.","opus":"Cryptic imagery of siege, submission and deceit, insisting that nothing is solid or certain and grief has been abandoned."},"linkin-park~with-you":{"src":"haiku","haiku":"Longing for an absent lover and memories haunting waking life.","sonnet":"Holding onto the memory of someone emotionally distant, haunted by a troubled past together that can't be undone.","opus":"Clinging to the memory of a lost, emotionally distant partner after a destructive relationship, unable to bring them back yet still hoping."},"nine-inch-nails~the-hand-that-feeds":{"src":"haiku","haiku":"Questioning blind obedience to authority and willingness to challenge control.","sonnet":"A challenge to passive obedience under political or religious authority, urging people to question and resist blind compliance.","opus":"Challenging blind obedience and religious or political authority, daring the listener to question the system and rebel against it."},"nine-inch-nails~somewhat-damaged":{"src":"haiku","haiku":"Cumulative disappointment and psychological collapse from unmet promises.","sonnet":"Collapse into self-destruction and emotional ruin after being abandoned by someone who promised to be there.","opus":"Bitter emotional collapse and abandonment, feeling broken and poisoned after idolizing someone who was absent when needed most."},"machine-head~aesthetics-of-hate":{"src":"haiku","haiku":"Honoring a fallen brother against disrespect and defending his memory fiercely.","sonnet":"A furious defense of a fallen comrade against a critic who disrespected his memory after his death.","opus":"Furious defense of a murdered friend's honor against a hateful critic, vowing vengeance and damnation for the attacker."},"nine-inch-nails~march-of-the-pigs":{"src":"haiku","haiku":"Consumption, greed, and violent destruction of systems and institutions.","sonnet":"Contempt for a conformist, greedy crowd of followers who are manipulated and fed what those in power want them to consume.","opus":"Sadistic craving to watch the powerful ('pigs') be torn down and destroyed, reveling in appetite, cruelty and domination."},"dragged-under~instability":{"src":"haiku","haiku":"Self-inflicted mental torment and accepting responsibility for one's own misery.","sonnet":"Self-awareness of depression, stagnation, and self-sabotage, recognizing oneself as the source of one's own misery.","opus":"Self-inflicted mental instability and depression, accepting that one's own bitterness and inertia, not others, is the source of misery."},"machine-head~clenching-the-fists-of-dissent":{"src":"haiku","haiku":"Anti-war protest against militarism, propaganda, and senseless violence.","sonnet":"Anti-war rage against government propaganda, corporate war profiteering, and the sacrifice of young lives for oil and power.","opus":"An anti-war protest against government propaganda, patriotic manipulation, and blood spilled for oil, urging nonviolent revolution."},"bring-me-the-horizon~kingslayer-feat-babymetal":{"src":"haiku","haiku":"Breaking free from control systems and awakening to liberation.","sonnet":"A call to break free from a corrupt, controlling system and join a rebellious savior figure to fight back.","opus":"Rallying a corrupted, controlled person to break free from their strings and rebel, framed in cyber-dystopian battle imagery."},"ocean-grove~sex-dope-gold":{"src":"haiku","haiku":"Cynicism about materialism and excess in modern shallow pursuit of pleasure.","sonnet":"The hollow, compulsive pursuit of pleasure — sex, drugs, and money — that leaves the narrator laughing bitterly at its own emptiness.","opus":"The empty, self-destructive chase after sex, drugs and wealth, laughing through loneliness and suffering while craving ever more."},"pro8l3m~molly":{"src":"haiku","haiku":"Hedonistic party lifestyle, wealth display, and sexual conquest.","sonnet":"A boastful night of VIP excess — luxury cars, alcohol, drugs, and women — with a sharp-tongued Polish rap bravado.","opus":"Hedonistic bragging about a lavish, chaotic party of drugs, luxury, women and money, living recklessly like Mick Jagger."},"linkin-park~by-my-self-remix":{"src":"haiku","haiku":"Existential paralysis and inability to trust anyone or make decisions.","sonnet":"The paralysis of self-doubt and social anxiety, unable to trust others or oneself while feeling permanently stuck on the outside.","opus":"Paralyzing self-doubt, distrust and fear of failure, feeling unable to rely on oneself or anyone while isolated and stretched thin."},"slayer~jihad":{"src":"haiku","haiku":"Religious violence and holy war justified by faith in God.","sonnet":"The September 11 attacks narrated from the perspective of a hijacker framing the act as holy war and martyrdom.","opus":"A chilling depiction of holy war and religious terrorism, voiced as a jihadist's fanatical instructions to kill nonbelievers in God's name."},"ocean-grove~junkie":{"src":"sonnet","sonnet":"A self-celebratory band manifesto about their distinctive, hard-hitting sound and loyal fanbase who bang their heads to it.","opus":"A self-referential party anthem hyping the band's bass-driven sound and their crowd of head-banging 'familiar junkies.'"},"ocean-grove~cali-sun":{"src":"haiku","haiku":"Addiction, depression, and melancholy romance in California culture.","sonnet":"Disillusionment and emotional sickness beneath the glamorous surface of Los Angeles, numbed by drugs and chasing a distant love.","opus":"Feeling sick, sad and drugged amid the glamorous emptiness of California, chasing love and escape while numbing on pills."},"system-of-a-down~war":{"src":"haiku","haiku":"Historical religious crusades and justified violence against non-believers.","sonnet":"The religious and political manipulation behind holy wars, questioning why men kill each other in the name of God.","opus":"A critique of holy war and the Crusades, questioning whether faith or greed for riches drives men to kill in God's name."},"crystal-castles~celestica":{"src":"sonnet","sonnet":"A desire to be left alone to fade away and disappear, rejecting comfort or rescue from an indifferent world.","opus":"Surrendering to oblivion and death, asking not to be found or saved, amid cryptic imagery of cleansing and letting go."},"ocean-grove~thousand-golden-people":{"src":"haiku","haiku":"Apocalyptic vision of humanity's decline and societal decay.","sonnet":"Passive drift through a technologically numbing world where humanity watches itself decay without connection or urgency.","opus":"An uneasy meditation on facing the future, mortality and numb detachment as one watches a fading world go by."},"northlane~bloodline":{"src":"haiku","haiku":"Generational trauma and inescapable toxic family bloodline.","sonnet":"Growing up in a chaotic, neglectful household under drug-addicted parents and escaping that toxic inherited trauma alone.","opus":"Escaping a hellish childhood shaped by drug-addicted parents, carrying their bad blood and trauma while surviving on one's own."},"queens-of-the-stone-age~you-think-i-ain-t-worth-a-dollar-but-i-feel-like-a-millionaire":{"src":"sonnet","sonnet":"A high-energy, fragmented ode to heavy rock excess — toro (bullishness), booze, B-movies, and raw appetite for more.","opus":"A hedonistic radio-framed anthem of craving and excess, demanding ever more indulgence, thrills, gore and gratification."},"ocean-grove~superstar":{"src":"haiku","haiku":"Sexual attraction and infatuation with a mysterious woman.","sonnet":"Infatuation with a captivating woman whose presence and movement take over the narrator's mind entirely.","opus":"Infatuation and desire for a captivating woman who dazzles the narrator, mixing romance, ego and ecstatic escapism."},"machine-head~halo":{"src":"haiku","haiku":"Rejecting religious hypocrisy and fighting oppressive faith-based systems.","sonnet":"Anti-religious defiance against the Christian right's political power, rejecting their God and refusing to submit.","opus":"A militant attack on organized Christianity and the religious right, refusing to pray and vowing to fight their hypocrisy over abortion rights."},"nine-inch-nails~the-big-come-down":{"src":"sonnet","haiku":"Internal struggle and descent into despair and emotional breakdown.","sonnet":"An inescapable inner hatred and self-destructive spiral that the narrator cannot outrun no matter where they go.","opus":"Self-destructive craving to hit rock bottom, smashing everything apart as inner hatred and misery keep rising from within."},"type-o-negative~everything-dies":{"src":"haiku","haiku":"Mortality, grief over lost loved ones, and universal human death.","sonnet":"Grief over the deaths of family members and the universal fact that everything and everyone dies.","opus":"Grief and existential despair over mortality, mourning dead relatives and dreading the death of everyone loved, including oneself."},"bring-me-the-horizon~teardrops":{"src":"sonnet","haiku":"Emotional numbness and suicidal ideation masked by substance use.","sonnet":"Emotional numbness and suicidal ideation — feeling emptied out until even sadness runs dry, trapped in one's own dark mind.","opus":"Emotional numbness, depression and self-destruction, feeling drained and empty while high, isolated and turning against oneself."},"machine-head~blood-for-blood":{"src":"haiku","haiku":"Betrayal by close ally and violent retribution for violation of trust.","sonnet":"Demanding respect through physical retaliation against a false friend who exploited and betrayed the narrator.","opus":"A vow of retaliatory violence and demand for respect, repaying betrayal and disrespect with beatings under a 'blood for blood' code."},"nine-inch-nails~heresy":{"src":"haiku","haiku":"Attacking Christianity as destructive manipulation and hypocrisy.","sonnet":"A wholesale rejection of Christianity and organized religion as a hypocritical, manipulative institution built on invented divinity.","opus":"An atheist attack on Christianity, declaring God dead and condemning religion as a man-made instrument of suffering and control."},"the-dillinger-escape-plan~milk-lizard":{"src":"haiku","haiku":"Toxic sexual obsession and predatory desire masked as love.","sonnet":"A toxic sexual attraction to a manipulative woman who takes from the narrator while offering only pain in return.","opus":"A predatory, sadomasochistic sexual encounter with a wounded woman, tangled in mutual manipulation and inevitable estrangement."},"nine-inch-nails~survivalism":{"src":"haiku","haiku":"Survival instinct and indifference amid propaganda and violence.","sonnet":"Societal indifference to destruction — consuming violent media, abandoning the suffering, and choosing self-interest over solidarity.","opus":"Ruthless survivalism amid societal collapse, embracing propaganda and violence and abandoning others to save oneself."},"combichrist~never-surrender":{"src":"haiku","haiku":"Mental anguish and refusal to surrender despite suffering and despair.","sonnet":"Enduring shame, self-punishment, and mental anguish while refusing to surrender or be broken by the pain.","opus":"Self-medicating through guilt and despair, refusing to surrender despite suffering, and rising from one's own ashes."},"aimer~insane-dream":{"src":"haiku","haiku":"Psychological breakdown and fragmented trauma memories.","sonnet":"A desperate, haunted plea for forgiveness and release from traumatic memories that suffocate and will not fade.","opus":"A tormented, nightmarish struggle with painful memories and desperate prayers for forgiveness, trying to shake free of an insane dream."},"limp-bizkit~my-generation":{"src":"haiku","haiku":"Generational apathy and defiant nihilism of Gen X youth.","sonnet":"Generational defiance — a disillusioned youth culture demanding to be taken seriously and refusing to care what others think.","opus":"A defiant, party-hard generational anthem of not caring what critics say until they respect the narrator's disaffected generation."},"magdalena-bay~chaeri":{"src":"haiku","haiku":"Regret for hurting a close friend and inability to escape cycles of harm.","sonnet":"Regret over failing a friend named Chaeri who was struggling with depression, wishing past comfort had been offered sooner.","opus":"Regret and guilt over failing a depressed friend named Chaeri, wishing one had said the right words to help them."},"machine-head~elegy":{"src":"haiku","haiku":"Environmental destruction and Earth's suffering from human exploitation.","sonnet":"A lament for environmental destruction — pollution, deforestation, and acid rain — treated as humanity's crime against the earth.","opus":"An ecological lament for a poisoned, dying Earth, mourning pollution and humanity's destruction of nature as a requiem."},"nine-inch-nails~echoplex":{"src":"sonnet","haiku":"Emotional isolation and psychological withdrawal from the world.","sonnet":"Retreating into an interior fortress of self-isolation, becoming unreachable and letting one's voice echo back to oneself alone.","opus":"Retreating into an isolated inner fortress rebuilt from a broken self, feeling safe, detached and untouchable from others' torment."},"pro8l3m~2-17":{"src":"haiku","haiku":"Digital exploitation and cybercrime threatening personal security and privacy.","sonnet":"Total digital surveillance and data exploitation — everything you do online is tracked, hacked, and owned by unseen others.","opus":"A menacing warning about digital surveillance and hacking, threatening to seize someone's phone, accounts and money in minutes."},"pro8l3m~hazard":{"src":"haiku","haiku":"Urban alienation, drug use, paranoia, and self-destruction.","sonnet":"A night of gambling, drinking, and drugs in a seedy atmosphere, drifting on money, vice, and street-level paranoia.","opus":"A bleak, drug-fueled gambling scene of betting, cocaine, women and paranoia, chasing luck amid grim addiction and risk."},"nine-inch-nails~closer":{"src":"haiku","haiku":"Raw sexual desire and using another person to approach transcendence.","sonnet":"Using raw, animalistic sex to escape self-loathing and a flawed existence, seeking transcendence through physical union.","opus":"Obsessive, self-loathing sexual desire, using degrading sex with another to escape oneself and feel closer to God."},"pro8l3m~na-audiencji":{"src":"haiku","haiku":"Seduction leading to rough sexual encounter.","sonnet":"An explicit, graphic sexual encounter narrated in boastful detail from start to finish.","opus":"Graphic, boastful account of a rough sexual encounter in a lavish apartment, ending on a disturbing note of violence."},"dragged-under~here-for-war":{"src":"haiku","haiku":"Choosing confrontation and standing firm against someone who has failed you.","sonnet":"Cutting off a chronically failing, unreliable person and finding the strength to stand alone without them.","opus":"Cutting off an ungrateful, self-sabotaging person who squandered every chance, declaring independence and readiness to fight on without them."},"machine-head~wipe-the-tears":{"src":"haiku","haiku":"Overcoming hardship and maintaining inner strength through persistent struggle.","sonnet":"Persisting through years of failure, rejection, and hardship and refusing to give up on life or one's own resilience.","opus":"Enduring years of pain, failure and rejection but refusing to give up, wiping away tears and fighting for what one loves."},"eisbrecher~verr-ckt":{"src":"sonnet","haiku":"Social alienation and threat of explosive breakdown from repression.","sonnet":"Embracing one's own madness and difference as freedom, celebrating being unhinged rather than conforming to normality.","opus":"Embracing one's own madness and menace, taunting a hypocritical, fearful other while blurring who is truly normal or sick."},"kyuss~one-inch-man":{"src":"haiku","haiku":"Emotional isolation and loneliness of a small, overlooked man.","sonnet":"A small, lonely man craving intimacy and connection, wondering if anyone could truly want or hold him.","opus":"A lonely soul aching for connection and physical intimacy, doubting whether the desired person truly wants to hold him."},"wargasm-uk~pyro-pyro":{"src":"haiku","haiku":"Mental breakdown and burning down systems while drowning in despair.","sonnet":"Pandemic-era lockdown rage — claustrophobia, collective mental breakdown, and the urge to burn down the system confining everyone.","opus":"Feeling trapped, suffocated and driven to the brink of insanity, threatening to burn everything down if kept caged."},"machine-head~imperium":{"src":"haiku","haiku":"A person refuses to be controlled or defined by others' expectations and prejudice, standing defiantly against external pressure to conform or submit.","sonnet":"A declaration of self-reclamation against societal conditioning and prejudice, where the speaker vows to break free from imposed chains, convert fear and rage into strength, and take back control of their own life.","opus":"A defiant declaration of self-liberation, in which the speaker refuses to be a slave to society, prejudice, and self-doubt, vowing to turn every weakness, rage, and fear into strength and take back control of his own life."},"nine-inch-nails~gave-up":{"src":"haiku","haiku":"After someone changed the speaker's sense of self, they descend into self-destruction and despair, caught in a cycle of trying and failing to escape the damage.","sonnet":"A portrait of total self-destruction: the speaker has systematically dismantled their own sanity, integrity, and sense of self, arriving at a point of resigned surrender after repeatedly trying and failing to hold together.","opus":"A song about self-destruction and despair, in which the speaker describes smashing everything he believed in and valued, hating what he has become, and ultimately giving up after trying and failing."},"linkin-park~numb":{"src":"haiku","haiku":"Emotional numbness and loss of identity develop from being pressured to live under someone else's expectations and rules rather than as oneself.","sonnet":"The speaker is exhausted by the pressure of living up to someone else's expectations, feeling emotionally deadened by the constant sense of falling short, and asserting a need to reclaim their own identity rather than conform.","opus":"A song about being worn down by someone else's expectations, where the speaker feels smothered and constantly judged, and grows numb and detached while longing to be himself instead of who the other person wants him to be."},"linkin-park~papercut":{"src":"haiku","haiku":"Internal paranoia and anxiety manifest as an inner critical voice that judges every action and witnesses every lie, creating persistent self-doubt.","sonnet":"The speaker is consumed by a paranoid inner voice — an imagined face beneath the skin — that catalogues every mistake and lie, and the lyric suggests this same self-critical consciousness exists inside everyone.","opus":"A song about paranoia and self-scrutiny, describing an inner \"face\" that watches, judges, and points out every mistake and lie, a relentless internal voice the speaker cannot silence."},"linkin-park~faint":{"src":"haiku","haiku":"The speaker experiences emotional distance and one-sided effort in a relationship, feeling unheard and ignored while desperately trying to be acknowledged.","sonnet":"The speaker feels chronically invisible and dismissed by someone who refuses to acknowledge them, and the song escalates from quiet hurt at being ignored to a furious demand to finally be heard.","opus":"A song about insecurity and desperation in a one-sided relationship, where the speaker pleads not to be ignored or turned away by someone he clings to, insisting his feelings are real and demanding to be heard."},"linkin-park~from-the-inside":{"src":"haiku","haiku":"Exhaustion from broken trust and inability to rely on someone leads to withdrawal and refusal to invest in the relationship any longer.","sonnet":"Worn down by deceit and broken trust in a relationship, the speaker resolves to cut off emotionally — stripping out everything they gave — and swears they will no longer risk themselves on someone who has proven untrustworthy.","opus":"A song about broken trust and exhaustion from deceit, where the speaker feels isolated from everyone and resolves to throw away his feelings and stop trusting himself with a person who drains him."},"babymetal~starlight":{"src":"haiku","haiku":"A journey of searching and flying toward light and hope, with commitment to never forgetting the brightness and connection that binds people together.","sonnet":"A song about persisting through separation and distance, urging flight toward a guiding starlight and promising that wherever either person ends up, the bond and the memory of that light will never be forgotten.","opus":"A song about soaring beyond time and distance toward a distant light, promising to always stay with and never forget a loved one, keeping their memory alive like a shining, shooting star."},"nine-inch-nails~discipline":{"src":"haiku","haiku":"The speaker needs external discipline and control from a partner because internal self-control has worn away and they cannot stop their own destructive impulses.","sonnet":"The speaker craves external restraint from another person because, once a compulsive pattern starts, they are unable to stop themselves — the song maps a loss of self-control and a dependent need for someone else to impose limits.","opus":"A song about craving control and structure from another person, where the speaker admits he cannot stop himself once he starts and needs discipline, help, and clearly defined limits, blurring where he ends and the other begins."},"ozzy-osbourne~let-me-hear-you-scream":{"src":"haiku","haiku":"An anthem celebrating survival, resilience, and vocal defiance in the face of struggle; the imperative to fight hard and make noise in adversity.","sonnet":"A call-to-arms demanding full-throated, uncompromising effort: the speaker, battered but unbroken, goads an audience to commit entirely rather than hold back, framing the moment as a final stand where going quietly is not an option.","opus":"A combative, taunting song urging a rival or listener to fight loudly and go all out in a do-or-die confrontation, with the speaker vowing to break them down and demanding to hear them scream."},"babymetal~kagerou":{"src":"haiku","haiku":"Wavering and flickering emotions—jealousy, hope, and burning passion—oscillate like a heat haze, never settling into stable ground.","sonnet":"The lyrics circle around something that cannot be hidden or denied — swaying and falling like a pendulum, rising and burning with jealousy — portraying an emotional state of barely-contained, wavering feeling that the speaker knows is obvious to the other person.","opus":"A song about suspicion and jealousy in which the speaker senses that concealment and evasion will not hide the truth, using a swaying pendulum and rising heat haze as images of flickering hope, falling petals, and a burning flame of envy."},"queens-of-the-stone-age~first-it-giveth":{"src":"haiku","haiku":"A cyclical, manipulative relationship dynamic where one person alternates between offering affection and taking it away, leaving the other dependent and confused.","sonnet":"The song describes being hooked on something — or someone — that grants pleasure only to take it away, leaving the speaker dangling, desperate, and aware that the cycle of getting and losing will keep repeating.","opus":"A song about a cruel, deceptive entanglement that first gives and then takes away, leaving the speaker begging, hooked, and toyed with as fortunes turn over time."},"linkin-park~a-place-for-my-head":{"src":"haiku","haiku":"Resentment toward someone who makes emotional demands and extracts energy under the guise of past kindness; the speaker seeks escape and rest.","sonnet":"The speaker resents a person who does favors only to demand repayment, using the image of the sun and moon to explain the one-sided dynamic, and ultimately tells them to leave so they can find peace away from the manipulation.","opus":"A song about resentment toward a greedy, controlling person who gives favors only to demand things back, as the speaker, sick of the tension, wants to break free and find peace of his own away from them."},"type-o-negative~i-don-t-wanna-be-me":{"src":"haiku","haiku":"Existential self-rejection and refusal of one's own identity; the speaker's life is marked by failure and the desire to cease being.","sonnet":"Through the story of a man who lives in mounting failure and dies alone in the snow, the song expresses a deep wish to shed one's own identity, while the closing request — celebrate at the wake, don't mourn — frames that self-rejection with dark resignation.","opus":"A song about self-loathing and a wish to no longer be oneself, framed around a man who lives poorly, dies alone in the snow, and a request that his wake be a celebration rather than a mournful gathering in black."},"nine-inch-nails~head-like-a-hole":{"src":"haiku","haiku":"Rejection of control and manipulation by a dominating force that exploits others; refusal to submit or bow down despite coercion.","sonnet":"A fierce refusal to submit to the power of money and greed, personified as a god that demands worship and tramples the sick and powerless, with the speaker insisting they would rather die than surrender their autonomy to it.","opus":"A song attacking the worship of money as a false god, refusing to surrender control to it and declaring one would rather die than obey, while condemning its indifference and greed."},"linkin-park~points-of-authority-cristal-remix":{"src":"sonnet","sonnet":"The speaker confronts someone who projects their own damage onto others — demanding authority they haven't earned, hurting people to share their pain — while also acknowledging being drawn into self-harm as a way to strike back at that person.","opus":"A song aimed at a controlling, self-righteous person who takes pleasure in others' pain and repeats the harm they learned, while the speaker describes his pride broken and even hurting himself to strike back at them."},"queens-of-the-stone-age~go-with-the-flow":{"src":"haiku","haiku":"Acceptance of impermanence and the realization that connections and memories ultimately don't matter; letting go without resistance or regret.","sonnet":"The song captures a mood of detachment and mild nihilism — people fall in and out of love, discard things, and go along without conviction — while the speaker admits wanting something worth dying and living for rather than just drifting.","opus":"A song about detachment and passivity in a fleeting relationship, where the speaker shrugs that nothing matters anymore even as he wants something worth dying for and living beautifully, willing to just go with the flow."},"linkin-park~don-t-stay":{"src":"haiku","haiku":"Ending a relationship and reclaiming individual identity after being damaged and changed by another person's influence and faithlessness.","sonnet":"The speaker demands the end of a relationship that has eroded their sense of self, asking the other person to take their faithlessness and go, and insisting on reclaiming their own identity rather than being slowly worn away.","opus":"A song about needing to end a toxic relationship, where the speaker asks the other person to leave, forget their shared memories, and give him himself back, insisting he no longer needs them wasting him away."},"nine-inch-nails~only":{"src":"haiku","haiku":"Isolation and realization that a relationship was imaginary—created by the speaker themselves as a vehicle for self-inflicted emotional harm.","sonnet":"The speaker recognizes that a significant other may have been a self-constructed fiction used as a tool for self-inflicted pain, and concludes by acknowledging that forcing their way through a sealed internal doorway has revealed something ugly on the inside.","opus":"A song about dissolving identity and self-isolation, in which the speaker feels himself fading and abstract, concludes that the other person was never real but something he invented to hurt himself, and realizes there is only himself."},"puddle-of-mudd~famous":{"src":"haiku","haiku":"Aspires to fame and hedonistic celebrity excess, willing to trade substance for the allure of wealth, status, and easy conquest.","sonnet":"The narrator fantasizes about achieving celebrity — the Oscars, the Grammys, partying with famous people — while acknowledging the warning that comes with it: be careful what you wish for, because fame brings jadedness and things falling apart.","opus":"A craving for celebrity and its excesses, cataloguing Hollywood parties, awards shows, money and easy sex, while warning to be careful what you wish for as fame can leave everything falling apart."},"the-dillinger-escape-plan~black-bubblegum":{"src":"haiku","haiku":"Confronts someone seeking shallow attention and temporary fame, warning them that their obsession with fleeting recognition will ultimately lead to regret.","sonnet":"A narrator turns on someone they once were captivated by, accusing her of self-delusion, attention-seeking, and a compulsion for notoriety — insisting he saw through the facade all along and that she is destined for regret.","opus":"A bitter address to a vain, attention-hungry person who thinks they're a special queen, with the narrator claiming he sees through the act, knows everything, and pairs their fleeting fame with regret."},"slipknot~left-behind":{"src":"haiku","haiku":"Grieves the loss and deterioration of friendships or relationships, watching people slip away while memories of connection and betrayal linger.","sonnet":"The narrator feels cut off from people and memories that have slipped away, caught between wanting to ignore a toxic presence and being pulled toward it, unable to fully let go.","opus":"Alienation, decay and betrayal, as the narrator feels everything slipping away and describes being left behind after being deceived by someone he now wants to keep at a distance."},"linkin-park~lying-from-you":{"src":"haiku","haiku":"A person breaks free from pretending to be someone they are not, realizing that conforming to others' expectations has corrupted their true self.","sonnet":"Someone who has spent years pretending to be the person others wanted them to be reaches a breaking point, recognising that the false self they performed has become part of them, and decides to break free even if it means hurting those who knew only that mask.","opus":"The exhaustion of maintaining a false self to please someone, as the narrator admits he pretended to be who others wanted and now lies his way out, realizing the worst part of the other person is himself."},"korn~spike-in-my-veins":{"src":"haiku","haiku":"Expresses internal torment and the drive to harness pain as power, refusing to be stopped by suffering or the judgment of others.","sonnet":"The narrator describes being driven by pain and a sense of betrayal while refusing to give in or be stopped, channelling rage and suffering into a relentless forward push against obstacles and external control.","opus":"Pain, rage and self-destruction under the pressure of doing what others demand, with the narrator lashing out, feeling insane and dangerous while pounding spikes into his veins."},"slayer~eyes-of-the-insane":{"src":"haiku","haiku":"Combat trauma haunts a soldier with vivid, intrusive memories of death and violence that break the mind into fragmented, tormented pieces.","sonnet":"A soldier is consumed by the psychological aftermath of combat — relentless flashbacks, mutilated faces haunting his dreams, shell shock and panic attacks that will not let him rest.","opus":"A soldier tormented by war, haunted by mutilated faces, flashbacks, panic attacks and shell shock, unable to rest as death keeps coming back for him."},"marilyn-manson~deep-six":{"src":"haiku","haiku":"Warns against self-deception and the danger of allowing someone into one's mind, using mythic imagery to suggest spiritual invasion and control.","sonnet":"The narrator describes a destructive relationship in which someone has invaded and rearranged his inner world, using imagery of wax feathers and artillery to convey a power imbalance, while invoking the myth of Narcissus as a warning against self-absorption.","opus":"A confrontation with a narcissistic, controlling figure, invoking Zeus's warning to Narcissus, as the narrator resists having his mind invaded and equates love with evil and sin."},"limp-bizkit~my-way":{"src":"haiku","haiku":"Someone asserts independence and refuses further submission to another's authority, choosing freedom and solitude over continued conflict.","sonnet":"Tired of being looked down on and controlled in a relationship or situation, the narrator declares he is done compromising and will leave on his own terms, doing things his way from now on.","opus":"A defiant break from someone's controlling leadership, with the narrator declaring he'll do things his own way, walk out, and let the other person be left missing him."},"a-perfect-circle~the-outsider":{"src":"haiku","haiku":"A speaker condemns another for self-destructive behavior and delusion, refusing to witness further self-sabotage and urging them to take their tragedy elsewhere.","sonnet":"The narrator confronts someone who is self-destructing — lying, threatening suicide, courting drama — with a mixture of exhausted frustration and cold ultimatum, telling them to go through with it somewhere far away if they truly mean it.","opus":"An exasperated plea to a self-destructive, attention-seeking person, urging them to stop their reckless, suicidal behavior, and coldly telling them to do it far away if they go through with it."},"linkin-park~figure-09":{"src":"haiku","haiku":"Someone realizes they have internalized and embodied the pain inflicted by another, becoming like their tormentor and unable to separate themselves from that hurt.","sonnet":"The narrator cannot stop thinking about someone who has left a lasting psychological mark on him; by expressing his pain he realises he has made it a permanent part of his identity, and now he desperately wants to expel that person from his mind.","opus":"How dwelling on the pain someone caused turns into an obsession, as the narrator realizes he took what he hated and made it part of himself, trying to let go and reclaim his own space."},"northlane~carbonized":{"src":"haiku","haiku":"Exposes deception and predatory behavior, predicting that when exposed to scrutiny the false persona will burn away and reveal the corruption beneath.","sonnet":"The narrator exposes a predatory figure who hid behind a false ally facade — using mirrors and smoke, exploiting those beneath him — and declares that once the light comes out, his true nature will be burned away and he will face the consequences.","opus":"An indictment of a manipulative, predatory person who uses smoke and mirrors and looks down on others, with the narrator vowing they'll be exposed and warning he has no heroes left."},"a-day-to-remember~paranoia":{"src":"haiku","haiku":"Paranoia and anxiety manifest as an invasive, all-consuming force that lodges in the mind and cannot be escaped no matter what is tried.","sonnet":"The song gives voice to an invasive, obsessive presence — described as a time bomb ticking inside someone's head — that fuels paranoia: the inability to sleep, fear of unknown callers, the sense of being watched and followed.","opus":"The grip of paranoia and dread, with sleeplessness, fear of unknown callers and footsteps, imagined as a ticking time bomb clouding judgement and lodged inside one's own head."},"bring-me-the-horizon~antivist":{"src":"haiku","haiku":"Critiques apathy and performative activism, arguing that real change requires leaving screens and taking real risks rather than empty posturing.","sonnet":"The narrator rails against hollow online activism and self-righteous posturing, arguing that the world is broken, those in power are predatory, and performative outrage only makes things worse — demanding real action or honest silence instead.","opus":"An angry, cynical rant against apathy and hollow activism, telling people fed up with the world to get off their screens and act, while insisting no revolution comes without blood."},"slayer~new-faith":{"src":"haiku","haiku":"Rejects religious belief and biblical authority, embracing heresy and personal power as liberation from faith-based systems of control.","sonnet":"The narrator rejects organised religion as a system of lies and control for weak minds, and invites listeners to abandon it in favour of a new, self-defined creed built on chaos, indulgence, and personal heresy.","opus":"A blasphemous rejection of religion, mocking a holy man's faith and rejecting biblical prophecy, as the speaker sets himself up as a false savior offering a new faith of indulgence and evil."},"strapping-young-lad~underneath-the-waves":{"src":"haiku","sonnet":"The narrator is exhausted by an endless cycle — fighting, lying, trying, waiting — and suggests that those who follow such patterns end up submerged and lost beneath the waves.","opus":"Weariness and futility, with the narrator sick of waiting, fighting and trying for nothing, longing for a new age while others are lost underneath the waves.","haiku":"The song expresses profound exhaustion with waiting, fighting, and false hope. A speaker buried in fatigue, lies, and waking dread names what lies beneath: something or someone submerged, lost, or gone for good."},"nine-inch-nails~every-day-is-exactly-the-same":{"src":"haiku","haiku":"Expresses the monotony and despair of a heavily controlled, repetitive existence where love is absent and the self is constantly suppressed.","sonnet":"A person trapped in a numb, repetitive existence — stripped of purpose, voice, and feeling — hides a secret message hoping someone will one day find it, clinging to a small remaining piece of selfhood buried beneath a hollow routine.","opus":"Numb, hopeless monotony, as the narrator repeats the same routine, feels neither love nor pain, has lost his voice and purpose, and can predict exactly how it all ends."},"raubtier~det-finns-bara-krig":{"src":"haiku","haiku":"A warrior's existence defined by ceaseless conflict and suffering, with only pain and struggle constituting life's fundamental nature.","sonnet":"The song describes the warrior's existence as an unending state of war: every dawn brings the sound of battle, every heartbeat is a skirmish, and the only fate waiting at the end of the path of hardship is a dark grave beneath a blood-red sky.","opus":"Sung in Swedish, it portrays a warrior's grim existence in which there is only war and life is struggle, with each breath and heartbeat marked by rage, pain and an eternal, deadly vigil."},"machine-head~old":{"src":"haiku","haiku":"Rejects religious hypocrisy and divine authority, embodying defiance against faith systems that have failed humanity.","sonnet":"The narrator attacks organised religion as a corrupt, centuries-old lie that feeds on greed and cruelty, presenting himself as an ancient, defiant force that no crown of thorns or holy authority can subdue.","opus":"Voiced by a blasphemous, anti-Christian figure who reigns over a corrupt, hateful world, defies religion, mocks Jesus, and boasts that attempts to blind, bury or drain him will fail."},"type-o-negative~christian-woman":{"src":"haiku","haiku":"Portrays sexual repression and shame intertwined with religious devotion, depicting a woman trapped between religious doctrine and bodily desire.","sonnet":"The song portrays a devout woman whose religious devotion is entangled with repressed sexual desire — her cross, her prayers, and her guilt converging in an interior conflict between faith and bodily longing.","opus":"A religious woman whose devotion becomes erotic, conflating worship of a suffering Christ with sexual desire and guilt over lust she believes will damn her."},"nine-inch-nails~last":{"src":"haiku","haiku":"A transient, temporary connection devoid of lasting meaning, with desire and addiction masking the inevitability of separation and decay.","sonnet":"The narrator, hollowed out by loss of purpose and self-respect, craves someone to enter him, fix him, and ultimately discard him — fully aware that whatever he seeks is temporary and that nothing can truly rescue him from his own decay.","opus":"Total self-loathing and surrender, as the narrator describes giving up, going all the way down, seeing through lies, and wanting someone to make, take, break and throw him away."},"rob-zombie~reload":{"src":"haiku","sonnet":"The lyrics circle around a commanding, godlike presence called Pin Eyed God and repeated commands to reload and prepare to die, but the imagery is too fragmented and abstract to yield a clear narrative subject.","opus":"A violent, chaotic scene built around loading a gun and 'time to die,' invoking a 'Pin Eyed God' amid disorienting imagery of destruction.","haiku":"A violent, cyclical vision of destruction and transformation: snapping magazines, blowing away, and reloading for another round. The repeated 'time to die' and the image of the 'Pin Eyed God' render an apocalyptic inevitability without escape."},"bloodhound-gang~foxtrot-uniform-charlie-kilo":{"src":"haiku","haiku":"Uses crude euphemisms to describe sexual acts while maintaining a playful, deliberate tone about physical intimacy without pretense.","sonnet":"The entire song is an extended exercise in euphemism, piling up comic slang phrases that all describe the same sex act, while the refrain spells out an obscenity in NATO phonetic alphabet.","opus":"A comedic sex song built entirely on absurd euphemisms and the spelled-out phrase 'fuck,' bluntly declaring the singer doesn't want to beat around the bush."},"bring-me-the-horizon~shadow-moses":{"src":"haiku","haiku":"Confronts the past and secrets that cannot be buried, trapped in an endless cycle of repetition where nothing ever truly ends.","sonnet":"The narrator thought he had buried and escaped something — a feeling, a memory, or a part of himself — only to find it has broken back through; the song frames this return as sempiternal, something that can never truly be killed off.","opus":"A sense of being trapped and going nowhere while living as if ready to die, confronting a buried past or enemy that refuses to stay dead in an endless, cyclical struggle."},"northlane~eclipse":{"src":"haiku","haiku":"Endures abuse and becomes a willing target for another's pain, yet refuses to become like their abuser.","sonnet":"The narrator addresses someone — likely a parent or guardian — who used fear and abuse to control them, resolving that despite carrying the marks of that treatment they refuse to become the same kind of person.","opus":"Standing up to an abuser who takes out their own fear, blame and shame on the narrator, who refuses to be afraid and vows he will never let himself become like his tormentor."},"northlane~talking-heads":{"src":"haiku","haiku":"Internal voices and self-doubt silence the mind while the person resists pharmaceutical escape, refusing to numb the internal chaos.","sonnet":"The narrator feels locked out of his own mind, unable to fit comfortably in his own skin, and overwhelmed by internal voices that drown out rational thought — resisting medication as a way out while searching for a sense of self.","opus":"A struggle with mental turmoil and intrusive voices, as the narrator feels locked out of his own mind, doesn't fit his skin, refuses medication, and is silenced by the 'talking heads' in his head."},"nine-inch-nails~the-idea-of-you":{"src":"haiku","haiku":"Separation and transformation leave only fragments; the narrator asks to be remembered as an idea rather than the deteriorated present self.","sonnet":"A dissociating speaker — uncertain whether his past self or a relationship even existed — urges someone to retreat back to a comfortable idealised image of him rather than witness whatever he is becoming, while an inner voice insists none of this is happening.","opus":"A fractured, dissociative confession in which the narrator insists something is wrong with him, disowns his own words and identity, and begs someone to go back to the idea of him rather than the reality."},"machine-head~bite-the-bullet":{"src":"haiku","haiku":"Encourages endurance and fierce determination, transforming hatred into fuel for overcoming weakness and breaking free from constraints.","sonnet":"The song is a direct address urging someone to convert pain and hatred into strength, to push through inner battles with ferocity and determination rather than yield.","opus":"A defiant call to endure pain and hardship, turning heart to steel and channeling hate into the will to win, urging a lion-hearted refusal to give in to weakness."},"massive-attack~girl-i-love-you":{"src":"haiku","sonnet":"The narrator acknowledges that his love for a woman is gone even as he misses her, recalling a promise she made to stay and expressing the difficulty of accepting that the bond has permanently ended.","opus":"A love that has faded, as the narrator tells a girl he still loves her but his love has gone forever, missing her while acknowledging the connection has ended.","haiku":"A love that has irreversibly faded. The speaker professes devotion yet acknowledges their own love is gone forever; back in Spanish town, a promise to never let down rings hollow against the reality of absence."},"nine-inch-nails~mr-self-destruct":{"src":"haiku","haiku":"An inner force of self-destruction speaks from within, claiming control over all aspects of life and identity, pulling toward ruin and addiction.","sonnet":"An omnipresent inner voice catalogues all the forces — religion, denial, addiction, violence — that it embodies and uses to control and destroy the person it inhabits.","opus":"A personification of self-destruction and control, an inner voice that claims to be one's hate, addiction, lies, religion and ruin, dragging the listener down while they let it happen."},"nine-inch-nails~terrible-lie":{"src":"haiku","haiku":"Confronts God over suffering and broken promises, expressing rage at faith betrayed and the world's darkness despite spiritual devotion.","sonnet":"The narrator accuses God of betrayal — of promising salvation and delivering only hatred, loneliness, and moral collapse — oscillating between rage and a desperate need for something to hold onto.","opus":"An anguished, accusatory address to God, demanding an apology and railing against a betrayal of faith, as the narrator, stripped of security and pride, still desperately wants someone to hold onto."},"redhook~fake":{"src":"haiku","haiku":"Denounces someone as a fraud whose false persona conceals predatory behavior and whose true colors emerge through betrayal and cruelty.","sonnet":"The narrator calls out someone they once admired who turned out to be a fraud — performing values they don't hold, wearing social awareness as a costume — and declares there is no bridge left between them.","opus":"A takedown of a hypocritical public figure whose kind image is a cover, accusing them of performative virtue, stealing others' work, and being exposed as a phony once their true colors show."},"celldweller~switchback":{"src":"haiku","haiku":"Regrets a choice made with lasting consequences from which there is no turning back or escape.","sonnet":"The narrator is trapped by an irreversible choice he regrets — chained to something he cannot reclaim — and the song turns on the impossibility of going back to who he was before.","opus":"Regret over an irreversible choice, as the narrator realizes it's too late to look back or undo what he can't reclaim, chained to a decision that means he'll never be the same."},"machine-head~beautiful-mourning":{"src":"haiku","haiku":"Sorrow and despair consume someone who faces their own violent reflection and confronts the end of hope.","sonnet":"The narrator describes a person in extreme psychological and emotional collapse — dissociating in front of a mirror, contemplating self-harm, consumed by depression — framing it as a final goodbye.","opus":"A descent into depression, self-hatred and suicidal despair, with the narrator not recognizing himself in the mirror, contemplating a razor at his wrist, and bidding a final goodbye."},"a-pale-horse-named-death~dmslt":{"src":"haiku","haiku":"Life feels meaningless and cruel, with a mind collapsing under the weight of existence and the desire to end it.","sonnet":"The narrator describes a life of unrelenting pain and failure in a world he experiences as cruel from birth, expressing an exhausted wish to simply lie down and die.","opus":"Exhaustion with a cruel, painful life, as the narrator feels his mind crumbling, sees no point in living or praying, and expresses a wish to lie down, take a pill, and let himself die."},"linkin-park~by-myslf-josh-abraham-and-mike-shinoda-reanimation":{"src":"haiku","haiku":"Questions whether to trust instinct or caution, unable to rely on the self when stretched between fear and the impossibility of genuine connection.","sonnet":"The narrator is paralysed by contradictory impulses — trust no one versus risk betrayal, fight back versus be overtaken — unable to rely on himself, stretched too thin, and feeling permanently stuck on the outside.","opus":"Being torn by self-doubt and distrust, as the narrator questions whether to trust others or no one, feels stretched too thin, and concludes he can't rely on himself."},"grimes~kill-v-maim":{"src":"haiku","haiku":"Refuses conventional behavior and restraint, accepting consequences for misbehavior while asserting personal autonomy despite systems trying to control them.","sonnet":"A defiant, rule-breaking narrator — invoking mob imagery and declaring a state of war against expected behaviour — insists on acting as he pleases despite external pressure to behave, describing a charismatic, dangerous energy he cannot fully control.","opus":"A brash, defiant persona who refuses to behave, boasting of getting into fights, getting away with it through connections, and having declared a state of war against being good."},"type-o-negative~life-is-killing-me":{"src":"haiku","haiku":"Medical institutions and authority figures exploit the vulnerable, turning life itself into a profitable instrument of suffering.","sonnet":"The narrator rages against the medical establishment as corrupt and incompetent, arguing that doctors are overpaid and useless, and demanding the right to die with dignity rather than be kept alive against his will on life support.","opus":"A scathing attack on doctors and the medical system, comparing physicians to executioners and quacks, and demanding the right to die with dignity rather than be kept alive to run up a bill."},"sodom~in-war-and-pieces":{"src":"haiku","haiku":"War and violence reduce people to fragments and decay, leaving only horror and the knowledge that death is inevitable.","sonnet":"The song dwells in an extreme landscape of mental collapse and physical carnage — fractured minds, rotting bodies, death and sewage — presenting war and psychic destruction as states that leave the self shattered and irretrievable.","opus":"Graphic depictions of war's carnage and madness, with corpses, mental decay and death, as the narrator leaves an enemy 'in war and pieces,' driving them insane with visions of slaughter."},"tankard~die-with-a-beer-in-your-hand":{"src":"haiku","haiku":"Celebrates metal devotion and defiant excess, framing alcohol-fueled rebellion and heroic defiance as the ultimate life choice.","sonnet":"Cast in the language of fantasy battle, the song celebrates a warrior ethos where fighting hard and drinking beer are fused into a single defiant last stand — die with honour, beer in hand.","opus":"A rowdy anthem of metal, battle and beer, mocking rivals who don't drink and vowing to make a final stand and die with a beer in hand."},"nine-inch-nails~we-re-in-this-together":{"src":"haiku","haiku":"Two people remain bound through destruction and pain, determined to survive together despite external forces trying to separate and damage them.","sonnet":"The narrator pledges absolute commitment to another person against a hostile world that wants to destroy what they have found together, declaring their bond unbreakable even as everything else falls apart.","opus":"A defiant devotion to a partner against a hostile world, as the narrator pledges that the two of them will make it through together no matter what tries to tear them apart."},"nutronic~icon":{"src":"haiku","haiku":"Seeks an icon or symbol to fill inner emptiness and provide meaning, grasping for faith in something transcendent.","sonnet":"The narrator, isolated and lacking belief in anything, reaches toward an idealised figure — an icon — to fill an inner emptiness, heal his doubts, and anchor him beyond his own disbelief.","opus":"A plea to an idealized 'icon' to fill an inner emptiness and give a reason to believe, as the narrator, full of disbelief and having fallen from grace, asks to be healed, anchored and freed from tormenting thoughts."},"machine-head~block":{"src":"haiku","haiku":"Hatred and corruption feed systems of control while media and ignorance keep people blind to the destruction of the poor.","sonnet":"The song catalogues systemic failures — racial division, media manipulation, poverty, corruption, pollution — and expresses total disgust with a society that perpetuates suffering while keeping people ignorant and blind.","opus":"An angry protest against societal corruption, racism, poverty, pollution and media manipulation, raging that hate breeds hate and the system feeds on the poor while people are kept blind."},"deadmau5~sofi-needs-a-ladder-ft-sofi":{"src":"haiku","haiku":"Roles reverse when attention shifts, with the pursuer becoming the pursued in a game of attraction and manipulation.","opus":"A power reversal in a toxic relationship, framed as musical chairs, in which the narrator flips the script on someone who tried to figure them out, promising they're about to get burned."},"nine-inch-nails~ruiner":{"src":"haiku","haiku":"Someone with infectious power deceives and corrupts others, gathering followers while destroying everything pure they touch.","sonnet":"The narrator addresses a manipulative, predatory figure who deceived and corrupted everyone around him — including the narrator — and ends by asserting, with increasing desperation, that none of the damage actually hurt him.","opus":"An accusation against a manipulative 'ruiner' who deceives followers and destroys everything he touches, coveting and corrupting what was the narrator's, who insists he wasn't hurt and can't be stopped."},"northlane~4d":{"src":"haiku","haiku":"Guilt and the burden of survival follow those who lost loved ones to overdose and tragedy.","sonnet":"The narrator reflects on losing someone to addiction or an overdose in a broken home and is left carrying guilt rather than grief — the weight of having survived and perhaps failed to prevent what happened.","opus":"Grief and survivor's guilt over losing someone to overdose in a broken home, as the narrator wrestles with the sense that someone like himself took the world away from them."},"rammstein~wiener-blut":{"src":"haiku","haiku":"A figure invites others into darkness and isolation beneath the surface, promising intimacy and eternity in solitude and sadness.","sonnet":"A captor lures victims — framed as children — into a cellar beneath his house, promising play and paradise while sealing them in darkness forever; the song depicts imprisonment and abuse through the voice of a predator who presents himself as protector.","opus":"Sung in German, it depicts a predatory captor luring a victim into a hidden underground room, welcoming them into darkness and imprisonment under the guise of pleasure and companionship."},"gorillaz~clint-eastwood":{"src":"haiku","haiku":"A mystical presence offers guidance and perception, helping others see beyond the material surface to inner spiritual understanding.","sonnet":"A rapping ghost or spirit describes itself as an invisible force running through nature and music itself, offering clarity and psychic guidance to those perceptive enough to see past surface reality — projecting confidence in a coming transformation.","opus":"A mix of weary optimism and mystical bravado, with a hook about feeling glad despite unhappiness and hope that the future is coming on, and a rapped verse casting the speaker as a spiritual guide who perceives destruction and offers survival through the mind."},"hollywood-undead~we-are":{"src":"haiku","haiku":"Broken, rejected, and overlooked people rise from the darkness of the city, demanding recognition for the dreams society ignores.","sonnet":"The song describes people forged from damage and broken beginnings — outsiders, addicts, the overlooked — who persist despite a brutal industry and world that discard them, finding solidarity in shared brokenness.","opus":"An anthem for the broken and overlooked, declaring that we are made from broken parts, chasing dreams in a hellish city of angels, and defiantly refusing to let anyone take away what's theirs."},"rammstein~rosenrot":{"src":"haiku","haiku":"A young man climbs to fetch a rose for his lover but both fall to their deaths, their desire leading to destruction.","sonnet":"Reworking the fairy-tale image of the rosebud on the cliff, the song tells of a young man who climbs a dangerous mountain to fetch a red rose for the girl who demands it; a stone gives way and both fall to their deaths — desire exacting its fatal cost.","opus":"Sung in German and echoing a folk tale, it tells of a girl who demands her beloved climb a mountain to fetch a rose for her, ending when a stone breaks loose and both fall to their deaths."},"limp-bizkit~eat-you-alive":{"src":"haiku","haiku":"Raw attraction and desire overpower a person, becoming an inescapable compulsion that consumes their thoughts.","sonnet":"The narrator is overwhelmed by physical attraction to a woman who ignores him, obsessively describing the pull she has on him while insisting there is nothing wrong with wanting someone who wants nothing to do with you.","opus":"Aggressive, obsessive lust for a woman who wants nothing to do with him, as the narrator fixates on her beauty and repeatedly declares he'd 'eat you alive.'"},"machine-head~davidian":{"src":"haiku","haiku":"A person hardens themselves against pain and disrespect, feeding on suffering and hatred until they become consumed by rage and violence.","sonnet":"A speaker fuelled by rage and hardship turns suffering into strength, feeding on pain and hatred to declare a violent, defiant freedom — the repeated shotgun-blast refrain signals a break from victimhood toward an unforgiving sense of power.","opus":"A defiant refusal to submit, channeling pain and street-bred rage into strength and calling for freedom won by violence. Suffering becomes purity and fuel, ending on the image of a wound with salt poured in it."},"machine-head~now-i-lay-thee-down":{"src":"haiku","haiku":"A haunting meditation on death and the ambiguous killing of a loved one, exploring whether the act was murder or mercy and questioning divine punishment.","sonnet":"A narrator grapples with having killed the person he loved, cycling through near-death imagery and tunnel-of-light hallucinations before arriving at guilt-ridden anguish — the song blurs whether the act was love or murder, and ends with a scream directed at God.","opus":"A narrator wrestling with death and a killing, haunted by whether it was love or murder, and screaming at God after having killed the one he loved. Imagery of dying, tunnels of light, and being laid down runs throughout."},"nine-inch-nails~the-day-the-world-went-away":{"src":"haiku","haiku":"A decay of communication and presence, where voices sound hollow and plastic, and a place exists that consumes fear and pain.","sonnet":"A figure perceived as hollow and decayed — his face a forced mask, his insides cold and grey — faces a reckoning whose cost is described as sweet but total, marking the day everything fell away.","opus":"A portrait of decay behind a false, plastic face, and a place that consumes fear and pain. It centers on the price paid on the day the whole world went away."},"nine-inch-nails~god-given":{"src":"haiku","haiku":"Religious manipulation and cult ideology that uses faith to divide people by race and class, claiming divine selection for some while condemning others.","sonnet":"A satirical portrait of religious self-righteousness: a preacher-figure claims divine authority, demands submission, and uses faith to exclude and dehumanise others, exposing how a sense of being \"chosen\" can become a cover for intolerance.","opus":"A bitter satire of religious certainty, voiced by self-declared chosen ones who claim divine sight while turning people away for their skin color and telling them to know their place. It exposes zealotry that separates the righteous from the 'swine.'"},"nine-inch-nails~suck":{"src":"haiku","haiku":"Sexual addiction and obsession portrayed as a compulsive force, where the speaker experiences shame and degradation while unable to resist.","sonnet":"A song about compulsive desire and self-disgust: the speaker is drawn irresistibly toward a figure who fuses pleasure with a corrosive sense of inner filth, comparing the craving to addiction and blasphemously to religious ecstasy.","opus":"A song of addiction and self-destruction cast in religious and sexual terms, where god is absent and the sickness is self-inflicted. The narrator feels dirty inside and wants to do terrible things."},"strapping-young-lad~s-y-l":{"src":"haiku","haiku":"A worker rejects corporate systems and institutional lies he encountered in low-wage labor, refusing to comply and reclaiming his defiance.","sonnet":"A first-person eruption of anger at a soul-crushing corporate existence — the speaker (referred to as Devy) describes being exploited, lied to, and diminished by a workplace system, before pivoting to a declaration of defiant self-determination and refusal to be controlled.","opus":"A furious rejection of a soul-crushing corporate job, spitting contempt at bosses, lies, and wasted opportunities while declaring the arrival of a defiant 'new age.' It builds into repeated shouts of 'fuck you' as a refusal to obey."},"nine-inch-nails~the-line-begins-to-blur":{"src":"haiku","haiku":"Loss of moral clarity and certainty about one's own identity and beliefs while trapped in an inescapable situation.","sonnet":"A speaker describes losing his sense of moral identity and self as isolation deepens — the boundary between who he was and who he is becoming dissolves, leaving uncertainty about whether anything or anyone has control over his descent.","opus":"A descent into confusion and self-erasure, where the longer the narrator stays inside himself the less clear anything becomes. Once sure which side he was on, he now watches the line blur as he disappears."},"pro8l3m~michael-de-santa":{"src":"haiku","haiku":"A Polish rap portrait of a man living a hedonistic, violent lifestyle in a palm-lined paradise, dealing with wealth, crime, and family chaos.","sonnet":"A first-person narrator moves through a sun-soaked, palm-tree city living out a GTA-style fantasy — armed confrontations, fast cars, casino nights, shady associates — pausing only for fleeting, irritated interactions with a wife and daughter before putting on goggles and heading back out.","opus":"A first-person crime fantasy narrated in the voice of a Grand Theft Auto-style gangster, moving through palm trees, drinks, drugs, shootings, and carjackings between casinos and family arguments. He treats mayhem as a game he can pause by taking off his goggles, blurring the line between player and character."},"machine-head~slanderous":{"src":"haiku","haiku":"Reclaiming slurs and insults as a response to systemic oppression, questioning internal hatred and division while resisting dehumanization.","sonnet":"The song reclaims every slur and marginalising label hurled at the outcast — addict, reject, deviant — and turns them into a statement of solidarity, asking why hatred of others might really be self-hatred, and calling out forces that divide and silence the vulnerable.","opus":"The narrator adopts every slur hurled at him as an outcast, turning bigoted names back on those who use them to divide and conquer. It hinges on the tension between loving and hating a brother, and whether that hatred is really self-hatred."},"a-pale-horse-named-death~when-crows-descend-upon-you":{"src":"haiku","haiku":"Death arrives in the form of black crows that feed on broken bodies and lies, inevitably claiming all souls regardless of their decay.","sonnet":"Death, figured as a pale horse and a murder of black crows, closes in on a person who is already breaking apart — the birds come from lies and wait for the body to rot, as time stops for no one and the soul is inevitably taken.","opus":"Crows gather over a dying, broken soul, tied to the lies that person told, while Death himself rides a pale horse to claim them. The imagery marks the approach and inevitability of dying."},"lia-lia~i-m-a-moth":{"src":"haiku","haiku":"Longing to transform into something beautiful while struggling with emotional pain and parental disconnection, eternally drawn to the moon.","sonnet":"A speaker compares herself to a moth — drawn helplessly toward light, unable to become the butterfly she might have been — weaving in childhood longing for parental love and the bittersweet, persistent pull of things that never quite disappear.","opus":"A speaker mourns being a plain moth rather than the pretty butterfly she could have been, tangling that self-image with a child's ache over whether her father loves her. Love is described as electric and painful, chased like shadows and apologized for."},"my-ticket-home~hyperreal":{"src":"haiku","haiku":"A sense of displacement and emptiness where the mind fragmented and detached, faking emotions while slipping into an unknown state.","sonnet":"A song about a disoriented, emotionally numb state — the speaker feels trapped somewhere between memory and the present, simultaneously locked in and left out, searching for a way to process or escape an unnamed inner strain.","opus":"A song about numb emptiness and dissociation, slipping into a flood of memory and staring into the void while faking away sorrow. The narrator feels locked in yet left out, counting down and asking to be cut loose."},"nine-inch-nails~branches-bones":{"src":"haiku","haiku":"Repetitive cycle of being trapped and erased, unable to escape sensations of decay and the familiar dread of a place once visited before.","sonnet":"A fragmented meditation on dissociation and loss of self: the speaker recognises that what he thought mattered has been shown to be false, that patterns he used to find comfort in no longer hold, and he just wants everyone to go away and leave him to his unravelling.","opus":"A disoriented, decaying state of mind where the narrator has been here before, no longer knows or cares, and his sense of self and memory fall apart. The lyrics dissolve into fractured, looping fragments about whether his thoughts and past ever really mattered, ending with a plea for everyone to go away."},"nine-inch-nails~beside-you-in-time":{"src":"haiku","haiku":"Separation and reunion across parallel spaces, as one person fades away from existence but promises reunion with another.","sonnet":"A speaker who has decided not to stay — likely facing death or departure — finds peace in the idea of fading away and being reunited with someone in a state that transcends time, framed as permanence rather than loss.","opus":"A meditation on parting and reunion, with the narrator sensing a loved one in parallel places as he decides to fade away. He promises they will never die and will be beside each other in time, over an endlessly repeating refrain."},"porcupine-tree~sleep-together":{"src":"haiku","haiku":"An escape from pressure and duty through mutual abandonment and erasure, leaving behind all traces of former identity.","sonnet":"Two people choose a complete exit from their lives — erasing files, burning possessions, abandoning the future — in a pact that frames escape as relief and a shared surrender as the only way to release pressure.","opus":"A pair plotting to erase all trace of themselves and escape their lives together, framed as fate and a final way out. Sleeping together becomes a way to relieve pressure and switch off the future for good."},"bring-me-the-horizon~the-house-of-wolves":{"src":"haiku","haiku":"Religious structures and faith built on lies crumble like a house of wolves, where death is the only salvation from corrupt belief systems.","sonnet":"A rejection of organised religion framed as confrontation: the speaker refuses to accept faith built on manipulation and fear, insisting the promised kingdom is nothing but a grave, and that the edifice of belief will ultimately burn.","opus":"A scornful rejection of religious faith, demanding a reason to believe while dismissing it as a sorry excuse and predicting the believer's 'house of wolves' will collapse and burn. It insists that after death the only kingdom awaiting is a two-foot-wide, six-foot-deep grave."},"nine-inch-nails~right-where-it-belongs":{"src":"haiku","haiku":"Reality and perception questioned as potentially illusory, exploring whether individual consciousness and identity are merely dreams.","sonnet":"A quiet but unsettling examination of constructed reality: the speaker asks whether the world, the self, and perceived safety are all illusions or mental projections, and whether most people are too afraid to look through the cracks and see what — or who — is really there.","opus":"A series of unsettling questions about whether reality is just an elaborate dream and the world exists only inside one's own head. It probes the fear of looking through the cracks and finding oneself utterly alone."},"blue-stahli~give-me-everything-you-ve-got":{"src":"haiku","haiku":"Defiance against someone's attempts to control and intimidate, standing stronger than expected and refusing to submit.","sonnet":"A defiant response to someone who uses fear and negativity as weapons: the speaker strips away the opponent's power by naming it clearly and declaring they can absorb and outlast anything thrown at them.","opus":"A defiant taunt aimed at an adversary whose only weapon is projected fear, with the narrator standing stronger than expected and refusing to be overtaken. He dares them to throw everything they have at him."},"karnivool~nachash":{"src":"haiku","haiku":"Being drawn into an overwhelming force that swells and consumes awareness, a pivotal moment where one becomes part of something larger.","sonnet":"A song about a moment of overwhelming transformation — something vast and beautiful and feared is taking over, and the speaker, who normally keeps his thoughts distant and out of reach, finds himself finally present in a pivotal, irreversible instant.","opus":"An account of a mind-altering, awe-filled experience that feels bigger than the self, both terrifying and beautiful as it takes over. It shifts into private struggle with fading colors, self-doubt, and the fear of having wasted a last chance."},"nine-inch-nails~sin":{"src":"haiku","haiku":"Betrayal and violation in an intimate relationship where purity was stolen and the speaker is used as a vessel for someone else's control.","sonnet":"A relationship defined by violation and control: the speaker gave up something pure and had it stolen, and now oscillates between anger at the other person and a self-flagellating acceptance of punishment and degradation.","opus":"A relationship framed as violation, where the narrator's purity was stolen and he sees himself as an effigy to be disgraced and replaced. He recognizes the compromise, the kiss and fist getting under his skin, and takes in the extent of his own sin."},"nine-inch-nails~capital-g":{"src":"haiku","haiku":"Greed and corruption overtake moral conviction when power is attained, leading to rationalization and indifference to suffering.","sonnet":"A first-person confession from a figure who has abandoned principle for self-interest and power — indifferent to war, inequality, and environmental destruction — revealing that greed (the capital G) is the new god he now serves.","opus":"A satirical monologue in the voice of a selfish, power-worshipping figure who dismisses climate concern, personal accountability, and the suffering of others. The 'capital G' he now worships is revealed to be greed itself."},"filter~the-best-things":{"src":"haiku","haiku":"Life's best things are inaccessible and never free, while everyone pursues the same empty game going nowhere.","sonnet":"A cynical song about stasis and futility: despite apparent freedom or fresh starts, everything keeps going nowhere, and the refrain insists that the best things in life are neither free nor available — the green light promises progress that never arrives.","opus":"A portrait of stalled, going-nowhere lives where green lights lead nowhere and rules no longer matter. The refrain insists the best things in life are neither free nor meant for the narrator."},"woods-of-ypres~december-in-windsor":{"src":"haiku","haiku":"A memory of loneliness and numbness from 2002, when at 22 the speaker felt too old and developed an appetite for self-destructive behavior.","sonnet":"A speaker recalls a specific winter — December 2002 in Windsor — when he was young, alone, and beginning to numb himself with alcohol, and finds that even now the memory of that emotional coldness still has power over him.","opus":"A lonely winter night of drinking to numb pain and forcing oneself out to feel alive, still haunted by someone whose touch would shatter him. It looks back on a cold December, feeling far older than his years and developing a taste for poison."},"nine-inch-nails~the-beginning-of-the-end":{"src":"haiku","haiku":"Complicity in one's own downfall through desperation and selfishness, where facing consequences marks the beginning of collapse.","sonnet":"A warning addressed to the complacent and self-serving: those who have climbed over others, depended on lies, and looked out only for themselves are now facing the consequences — a reckoning that is, paradoxically, both an ending and a beginning.","opus":"A warning that those who climbed over others and lived on lies will face their consequences. The refrain declares this reckoning the beginning of the end."},"rammstein~zwitter":{"src":"haiku","haiku":"A being that is self-sufficient and complete within itself, containing both genders and finding love and fulfillment within its own dual nature.","sonnet":"A celebration of being intersex or dual-gendered — the speaker describes being both sexes merged into one, self-sufficient and self-contained, capable of self-love and self-fertilisation, and delighted not to need anyone else.","opus":"Sung from the perspective of a hermaphrodite who is both sexes in one body and joyfully in love with himself, able to please and even impregnate himself without needing anyone else. The German lyrics revel in this self-sufficiency, kissing his own reflection and shrugging off insults."},"machine-head~wolves":{"src":"haiku","haiku":"A brotherhood of outcasts and the damaged who operate through violence and competition, seeking dominance without satisfaction.","sonnet":"A song about a brotherhood of the damaged and rejected — beaten, dysfunctional, unwanted — who find unity and ferocity in their shared suffering, turning against rivals and tyrants with pack-like aggression, even as they admit the victories bring no lasting satisfaction.","opus":"A brutal anthem of a violent brotherhood of outcasts who bury their rivals and bow to no tyrant, likened to a wolf pack driven by rage and loyalty. Even in victory there is no satisfaction, only the endless hunt."},"make-them-suffer~hollowed-heart":{"src":"haiku","haiku":"Trauma and assault leave someone appearing composed to others while internally broken, with demons haunting them in solitude.","sonnet":"Written on behalf of someone who has endured abuse or assault in private — outwardly composed but inwardly haunted — the song condemns the perpetrators as cowards and acknowledges the survivor's pain while affirming their worth.","opus":"An address to someone secretly suffering, crying themselves to sleep behind closed doors while hiding their pain and blaming themselves. The narrator calls the tormentors cowards and sees the hurting person as a hero rather than a victim."},"nevermore~the-termination-proclamation":{"src":"haiku","haiku":"A violent station where the powerless march to death, where systems murk the line between freedom and execution.","sonnet":"A bleak portrait of lives that are determined before they begin and extinguished by systems beyond their control — whether read as abortion, war, or institutional death, the song indicts the machinery that marches the powerless to their graves and strips them of will.","opus":"A grim vision of a violent system that marches people to their deaths, where all who enter are killed and free will is forgotten. It condemns a mechanical order in which the voiceless take their positions and die."},"slayer~cult":{"src":"haiku","haiku":"Organized religion portrayed as oppressive propaganda that breeds abuse and corruption, using faith to exploit and control vulnerable people.","sonnet":"An all-out assault on organised religion, accusing it of spreading violence, exploitation, and abuse — the speaker rejects Christianity entirely, naming it a contagion and aligning himself against the church's moral authority.","opus":"A blistering attack on organized religion, equating it with hate, fear, war, and exploitation, and casting Jesus and the Bible as instruments of oppression and corruption. The narrator declares open war on God and rejects the 'cult of purity.'"},"megadeth~holy-wars-the-punishment-due":{"src":"haiku","haiku":"Religious conflict drives bloodshed across borders while those preaching superiority hide their complicity, leading to violent retaliation.","sonnet":"A two-part song: the first part condemns killing in God's name and the self-righteous certainty of religious and political leaders; the second shifts to a personal revenge narrative — a man whose family was killed hunts down those responsible — with both halves linked by the theme of violence justified by ideology.","opus":"The first part condemns killing in the name of religion and the divisions that tear countries apart; the second shifts into a mercenary's tale of revenge and paid violence. Together they trace war, righteous posturing, and the fear of having one's very thoughts taken away."},"devin-townsend~life":{"src":"haiku","haiku":"Life's inevitable end approaches and transforms perspective on existence, where death levels all distinctions and individuality.","sonnet":"A meditation on the awareness that life is finite: the speaker urges living on one's own terms, resisting the pull to simply let time slip away, and frames the eventual reckoning with death as something to be faced rather than fled.","opus":"A reflection on facing mortality and owning one's limited time, urging living fully on your own terms rather than fading away. It repeats the reassurance of meeting again on the other side, while noting death levels everyone to the same ground."},"bloodhound-gang~ralph-wiggum":{"src":"sonnet","sonnet":"A collage of non-sequiturs and absurdist one-liners drawn from the character Ralph Wiggum — the song has no narrative or emotional throughline, existing entirely as comedic randomness strung together in the voice of an oblivious child.","opus":"The lyrics are a collage of nonsensical one-liners in the voice of a dim, childlike character, strung together with a mock pop-star chorus telling him to get off the stage. The backward-spelled 'join the navy' hidden in the refrain is its one recurring wink."},"limp-bizkit~why-try":{"src":"haiku","haiku":"Aggressive dominance and destruction of competitors through confidence and violence, with contempt for those who try to challenge or oppose.","sonnet":"A bravado-heavy battle rap framing the speaker as an unstoppable force who will destroy any rival — with boxing and street-fight imagery throughout — arguing that opponents are already beaten before they start.","opus":"A braggadocious battle rap taunting rivals and rap contenders with threats of destruction and violent knockouts. The narrator crowns himself the top predator, promising anyone who challenges him will fry."},"serj-tankian~cornucopia":{"src":"haiku","haiku":"Environmental destruction driven by ignorance and lust, where humanity exploits nature without understanding the consequences.","sonnet":"A song about humanity's destructive relationship with the natural world: we rape and exploit the Earth without understanding why it suffers, surrounded by escalating ecological disasters — hurricanes, tornadoes, tsunamis — while the speaker mourns a broken pact and wonders why we disfigure what is beautiful.","opus":"An eco-conscious lament weaving a strange love plea with images of humanity raping the Earth and reaping violent storms, hurricanes, and tsunamis as consequence. It muses on why people disfigure beautiful things while still hoping for extraordinary connection."},"aimer~closer":{"src":"haiku","haiku":"An inevitable tragic ending that the speaker knows approaches, standing trapped between pretense and a predetermined conclusion.","sonnet":"A song about the slow, inevitable end of a relationship or moment: the speaker watches colours fade, memories slip, and the distance grow, knowing how the story ends but moving toward it anyway — closer to loss, farther from escape.","opus":"A song of hiding behind lies while falling apart inside, clinging to fading memories and pain as the only stable reality. The narrator moves closer to and farther from a moment, certain that however the story unfolds, it always ends with a particular person."},"paradise-lost~channel-for-the-pain":{"src":"haiku","haiku":"Persistent loneliness and a refusal to engage with life, where suffering itself becomes the only constant in existence.","sonnet":"A speaker who lives alone and seems to have always lost — never choosing, never seeking, never demanding — finds that his very existence has become a conduit for pain, and accepts this not with resistance but with passive, broken endurance.","opus":"A study of isolation and passivity, where the narrator lives alone, never chooses, and expects only to lose. His very existence becomes a channel for pain as his mind breaks and he avoids seeking the truth."},"dragged-under~hypochondria":{"src":"haiku","haiku":"Genuine illness dismissed by others as psychological delusion, leading to desperation for medical validation that never comes.","sonnet":"A person convinced something is genuinely wrong with them is dismissed as paranoid by everyone around them: the song captures the terror of feeling ill and unheard, of losing the battle with one's own mind while the world insists there is nothing to fix.","opus":"A first-person account of health anxiety and being disbelieved, terrified of an illness others insist is only in his head. Torn between fear of dying and wanting to live, he wages a losing war with his own mind."},"bring-me-the-horizon~parasite-eve":{"src":"haiku","haiku":"An epidemic or plague spreads through a population that ignored warnings, where suspension and fear replace normal life and death becomes inevitable.","sonnet":"Using pandemic and infection imagery, the song frames a coming catastrophe as inevitable and uncontainable — society is unprepared, leaders are incompetent, and the question is not whether disaster will arrive but whether anyone will remember the lesson once it has passed.","opus":"A song about a spreading plague and mass panic, framed as a war rather than a mere warning, with fever, quarantine, and paranoia about hidden agendas. It questions whether people will remember the lesson once the infection is forgotten, and warns that no amount of hand-washing can escape it."},"deftones~prayers-triangles":{"src":"haiku","haiku":"Internal conflict between divine and demonic forces that render someone eternally imprisoned and spiritually enslaved.","sonnet":"A speaker trapped between an inner demonic force and the angels he tries to keep finds that prayers and mental constructs offer no release — the repeated refrain \"you will never be free\" describes a state of spiritual and psychological captivity with no visible exit.","opus":"A struggle with a godless demon awakening inside, feeling enslaved to forces slowly rotting the speaker from within. The refrain warns someone they will never be free, amid images of tearing one's own heart out."},"nine-inch-nails~sunspots":{"src":"haiku","haiku":"Transformation through obsession with another person who awakens and consumes the self, burning away what was previously real.","sonnet":"A speaker is overwhelmed by an irresistible force — figured partly as a woman, partly as a consuming inner drive — that pulls him out of his old life completely; by the end he has stared into the sun long enough to lose the sense of ever having been a coherent self.","opus":"A compulsive, self-destructive attraction the narrator can't disobey, tied to a woman who makes him feel real even as he burns everything down. He stares into the sun reviewing all he's done, sensing he could have been someone but can't stop what he's begun."},"system-of-a-down~p-l-u-c-k":{"src":"haiku","haiku":"Genocide and systemic extermination of a people requires armed response and restitution for stolen lives and dignity.","sonnet":"A furious response to genocide — specifically the Armenian Genocide, given the band's heritage — calling for recognition, restoration, and reparation, and arguing that revolution is the only answer to a crime of that scale.","opus":"A protest against genocide and the erasure of an entire people, calling for revolution, recognition, restitution, and reparation. It condemns a system that took the children and left the few survivors unfound."},"nine-inch-nails~you-know-what-you-are":{"src":"haiku","haiku":"Self-deception fails eventually when others recognize one's true nature, leaving no choice but to return to origins and accept reality.","sonnet":"A speaker who tried to pass as something he is not — patching over his flaws long enough to be accepted — has been found out, and now confronts himself (or someone like him) with the demand to stop pretending and acknowledge what he really is.","opus":"A song of self-loathing and exposure, where the narrator's attempt to patch over his flaws and sneak by ultimately rots away and is found out. The furious refrain, aimed at himself, demands he remember what he really is and where he came from."},"queens-of-the-stone-age~no-one-knows":{"src":"haiku","haiku":"Following rules and taking pills designed to control, while realizing internal fulfillment and connection exist but remain unknowable to others.","sonnet":"A speaker adrift — rules to follow, pills to swallow, drifting across deserts and oceans — describes surrendering to something or someone that possesses him entirely, recognising himself as a fool for it but unable to resist what feels like a hidden gift.","opus":"A disoriented drift through rules, pills, and desire toward someone the narrator both surrenders to and feels a fool for, journeying through a desert of the mind. It closes with a Spanish-language radio-DJ skit introducing the band."},"queens-of-the-stone-age~avon":{"src":"haiku","haiku":"A system for controlling and dispensing with people portrayed as simple and efficient, with no distinction between victims.","sonnet":"A brief, impressionistic sketch of observation and control — the speaker watches people moving in a haze, strings them up and cuts them down, and notes that free-range humans end up cooped regardless, leaving a sense of detached, cyclical manipulation.","opus":"A cryptic sketch of watching someone move through a park in a haze, laced with unsettling images of stringing things up and cutting them down and of 'free range humans' cooped up. The meaning stays elusive, built on repetition and detachment."},"megadeth~hangar-18":{"src":"haiku","haiku":"Secret military facility housing alien remains and cryogenic subjects under enforced amnesia, held behind impenetrable security.","sonnet":"A song about a secret government facility — Hangar 18 — where the speaker claims alien bodies and technology are stored, and where selective amnesia is used to silence anyone who gets too close to the truth.","opus":"A conspiracy narrative about a secret military installation storing foreign life forms in cryogenic suspension, hidden behind impenetrable walls. The narrator fears he has seen and knows too much, mocking the notion of 'military intelligence.'"},"nine-inch-nails~getting-smaller":{"src":"haiku","haiku":"Increasing erasure and powerlessness as individuality and voice are stripped away, leaving only obedience and fading away.","sonnet":"A portrait of slow erasure: the speaker has lost his grip, his voice, his sense of purpose, and now shrinks into invisibility — obeying, behaving, fading away — with a sardonic acceptance that the shrinking world is somehow okay, even as it clearly isn't.","opus":"A portrait of paranoia and diminishing self, where the narrator loses his grip, obeys, and fades into a faceless nobody in the crowd. He recalls once believing in achieving something great but can no longer tell what's real, resigning himself to his shrinking world."},"a-day-to-remember~bad-vibrations":{"src":"haiku","haiku":"Toxic emotional influence that permeates and corrupts, leaving the speaker emptied and heartless.","sonnet":"A song about absorbing someone else's toxicity: the speaker feels an external darkness pressing in — distorting perception, inducing numbness, and shaping identity — framed as a sickness he cannot escape and did not choose.","opus":"A song about inner darkness and consuming pain treated as a sickness and a choice one must live with. Bad vibrations surround and corrupt the narrator, casting shadows that reshape who he is each day."},"cage-the-elephant~aberdeen":{"src":"haiku","haiku":"Obsessive cyclical abuse from someone dangerously seductive, repeatedly burning the speaker emotionally.","sonnet":"A speaker repeatedly drawn back to someone who burns him — a relationship defined by compulsive return despite knowing it's destructive — the name Aberdeen anchoring a specific feeling of being unable to cut the cord.","opus":"A song about being repeatedly burned by a manipulative, creeping lover the narrator keeps returning to, cutting the cord only to look way back. Recognizing his own dark side and the toll of the cycle runs beneath the restless refrain."},"carcass~death-certificate":{"src":"haiku","haiku":"Death reduced to data and administrative record, stripped of meaning and memory in institutional systems.","sonnet":"A person reduced to data after death: cross-indexed, machine-coded, digitised into a statistical obituary — the song strips away any notion of legacy or meaning, leaving only a certificate and a database entry as the final trace of a life.","opus":"A bleak meditation on death reduced to bureaucracy, where a life is cross-indexed, dissected, and filed away as data. A person's only legacy becomes a statistical obituary and a certificate of death."},"architects~these-colours-don-t-run-feat-jon-green-of-deez-nuts":{"src":"haiku","haiku":"Deception and corruption pervade systems of power and freedom, where materialistic pursuit leads to spiritual death.","sonnet":"A critique of the American Dream and capitalist society: the streets are not paved with gold, freedom comes at a price, and beneath the surface lies deception, chemical numbness, and a grinding suburban futility that benefits those at the top.","opus":"A furious critique of the false promise of the 'land of the free,' where streets aren't paved with gold and corruption and deception pervade everything. It mocks forced reassurances that 'everything is fine' and blames the greedy for the rot."}};
